float4 DataMosh(float2 UV : TEXCOORD0) : COLOR
{
    // Original texture sample
    float4 originalColor = tex2D(inputTexture, UV);

    // Data moshing effect
    float2 moshedUV = UV + (fract(UV * 10.0) - 0.5) * 0.1;

    // Sample from a slightly offset position
